@Getter
public abstract class Filter<T extends Filter<T>> {
  protected Include include;
  @Getter protected final Map<String, String> queryParams = new HashMap<>();

  public T addQueryParam(String name, String value) {
    queryParams.put(name, value);
    return (T) this;
  }

  public T addQueryParam(String name, Boolean value) {
    queryParams.put(name, String.valueOf(value));
    return (T) this;
  }

  public void removeQueryParam(String name) {
    queryParams.remove(name);
  }

  public String getQueryParam(String name) {
    return name.equals("include") && include != null ? include.value() : queryParams.get(name);
  }

  public String getCondition() {
    return getCondition(null);
  }

  public abstract String getCondition(String alias);

  protected abstract String addCondition(List<String> conditions);
}

package org.openmetadata.service.apps.bundles.searchIndex;

import java.util.concurrent.ConcurrentHashMap;
import lombok.Getter;
import org.openmetadata.schema.system.StepStats;

@Getter
public class Stats {
  private final StepStats jobStats = new StepStats();
  private final ConcurrentHashMap<String, StepStats> entityStats = new ConcurrentHashMap<>();

  public void updateEntityStats(String entityType, StepStats stats) {
    entityStats.merge(
        entityType,
        stats,
        (existingStats, newStats) -> {
          existingStats.setSuccessRecords(
              existingStats.getSuccessRecords() + newStats.getSuccessRecords());
          existingStats.setFailedRecords(
              existingStats.getFailedRecords() + newStats.getFailedRecords());
          existingStats.setTotalRecords(
              existingStats.getTotalRecords() + newStats.getTotalRecords());
          return existingStats;
        });
  }
}

